class RuleGuardTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void subsetGuardRejectsFilterVarsNotAssuredByLeftInput() {
		Filter filter = new Filter(new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x")),
				new Compare(new Var("x"), new ValueConstant(VF.createIRI("urn:x")), Compare.CompareOp.EQ));
		PlanIr ir = TupleExprToIr.convert(filter);
		RuleCapture capture = filter("f", join("j", capture("left"), capture("right")), scalar("cond"))
				.match(ir, ir.root())
				.orElseThrow();

		RuleGuard.GuardResult left = vars("cond").subsetOf(shape("left").assured()).test(capture);
		RuleGuard.GuardResult right = vars("cond").subsetOf(shape("right").assured()).test(capture);

		assertFalse(left.ok());
		assertTrue(right.ok());
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}
}
